      version: -1
      name: Is the user willing to send an email and was a valid email address provided?
      description: Determines if the user wants to send an email and checks if the
        entered email address is valid.
      type: condition
      iscommand: false
      brand: ""
    nexttasks:
      '#default#':
      - "20"
      "yes":
      - "37"
    separatecontext: false
    conditions:
    - label: "yes"
      condition:
      - - operator: isNotEmpty
          left:
            value:
              complex:
                root: Email address of the contact of the asset
                filters:
                - - operator: match
